import axios from 'axios';
import React, { useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { buildApiUrl } from '../utils/api';
import { clearAdminSession, setActiveWorkspace, setAdminSession } from '../utils/adminSession';

axios.defaults.withCredentials = true;

const Signin = () => {
  const navigate = useNavigate();

  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState('');
  const [success, setSuccess] = useState('');
  const [error, setError] = useState('');
  const [forgotMode, setForgotMode] = useState(false);
  const [resetToken, setResetToken] = useState('');
  const [newPassword, setNewPassword] = useState('');

  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const tokenFromUrl = params.get('resetToken');
    if (tokenFromUrl) {
      setForgotMode(true);
      setResetToken(tokenFromUrl);
      setSuccess('Reset token loaded. Enter your new password below.');
    }
  }, []);

  const handleSubmit = async (event) => {
    event.preventDefault();
    setError('');
    setSuccess('');
    clearAdminSession();

    const normalizedEmail = email.trim().toLowerCase();
    const trimmedPassword = password.trim();

    if (!normalizedEmail || !trimmedPassword) {
      setError('Email and password are required');
      return;
    }

    setLoading('Signing you in...');

    try {
      const response = await axios.post(
        buildApiUrl('/api/signin'),
        {
          email: normalizedEmail,
          password: trimmedPassword,
        },
        {
          headers: {
            'Content-Type': 'application/json',
          },
        }
      );

      const signedInUser = response.data.user;
      setLoading('');
      setSuccess(response.data.message);

      if (signedInUser?.organization?.slug) {
        setActiveWorkspace(signedInUser.organization.slug);
      }

      if (signedInUser?.is_admin) {
        setAdminSession({
          email: signedInUser.email,
          name: signedInUser.username || 'Admin',
          isAdmin: true,
          role: signedInUser.role || 'admin',
          isVerified: signedInUser.is_verified,
          orgId: signedInUser.org_id || null,
          organization: signedInUser.organization || null,
        });

        setTimeout(() => {
          navigate('/admin', { replace: true });
        }, 500);
        return;
      }

      setTimeout(() => {
        navigate('/');
      }, 700);
    } catch (requestError) {
      setLoading('');
      setError(requestError.response?.data?.message || 'Invalid email or password');
    }
  };

  const handleForgotPassword = async () => {
    setError('');
    setSuccess('');

    if (!email.trim()) {
      setError('Enter your email first to prepare a reset link.');
      return;
    }

    try {
      const response = await axios.post(
        buildApiUrl('/api/password/request-reset'),
        { email: email.trim().toLowerCase() },
        { headers: { 'Content-Type': 'application/json' } }
      );
      const resetInfo = response.data.reset;
      setForgotMode(true);
      setResetToken(resetInfo?.token || '');
      setSuccess(
        resetInfo?.reset_url
          ? `Reset link prepared: ${resetInfo.reset_url}`
          : response.data.message
      );
    } catch (requestError) {
      setError(requestError.response?.data?.message || 'Unable to prepare reset link');
    }
  };

  const handleResetPassword = async (event) => {
    event.preventDefault();
    setError('');
    setSuccess('');

    if (!resetToken.trim() || !newPassword.trim()) {
      setError('Reset token and new password are required');
      return;
    }

    try {
      const response = await axios.post(
        buildApiUrl('/api/password/reset'),
        { token: resetToken.trim(), password: newPassword },
        { headers: { 'Content-Type': 'application/json' } }
      );
      setNewPassword('');
      setSuccess(response.data.message);
    } catch (requestError) {
      setError(requestError.response?.data?.message || 'Unable to reset password');
    }
  };

  return (
    <section className="auth-page auth-page--signin">
      <div className="auth-shell">
        <div className="auth-shell__panel">
          <p className="auth-shell__eyebrow">Welcome Back</p>
          <h1>Sign in and continue planning your next stay.</h1>
          <p className="auth-shell__lead">
            Access your account to move faster through room reservations,
            dining requests, and future hotel bookings.
          </p>

          <div className="auth-shell__highlights">
            <span>Quick access</span>
            <span>Secure sign-in</span>
            <span>Booking ready</span>
          </div>
        </div>

        <div className="auth-card">
          <div className="auth-card__header">
            <p className="auth-card__eyebrow">Returning Guest</p>
            <h2>Sign In</h2>
            <p>Enter your email and password to access your account.</p>
          </div>

          {loading && <div className="auth-alert auth-alert--info">{loading}</div>}
          {success && <div className="auth-alert auth-alert--success">{success}</div>}
          {error && <div className="auth-alert auth-alert--error">{error}</div>}

          <form className="auth-form auth-form--signin" onSubmit={handleSubmit}>
            <label className="auth-field auth-field--signin">
              <span>Email Address</span>
              <input
                type="email"
                placeholder="Enter your email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                required
              />
            </label>

            <label className="auth-field auth-field--signin">
              <span>Password</span>
              <div className="auth-password">
                <input
                  type={showPassword ? 'text' : 'password'}
                  placeholder="Enter your password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  required
                />
                <button
                  type="button"
                  className="auth-password__toggle"
                  onClick={() => setShowPassword((previous) => !previous)}
                >
                  {showPassword ? 'Hide' : 'Show'}
                </button>
              </div>
            </label>

            <button type="submit" className="auth-submit">
              Sign In
            </button>

            <button
              type="button"
              className="auth-password__toggle auth-password__toggle--inline"
              onClick={handleForgotPassword}
            >
              Forgot password?
            </button>

            <p className="auth-switch">
              Don&apos;t have an account? <Link to="/signup">Create one</Link>
            </p>
          </form>

          {forgotMode && (
            <form className="auth-form auth-form--signin auth-form--reset" onSubmit={handleResetPassword}>
              <label className="auth-field">
                <span>Reset Token</span>
                <input
                  type="text"
                  placeholder="Paste reset token"
                  value={resetToken}
                  onChange={(event) => setResetToken(event.target.value)}
                  required
                />
              </label>

              <label className="auth-field">
                <span>New Password</span>
                <input
                  type="password"
                  placeholder="Enter a new password"
                  value={newPassword}
                  onChange={(event) => setNewPassword(event.target.value)}
                  required
                />
              </label>

              <button type="submit" className="auth-submit">
                Reset Password
              </button>
            </form>
          )}
        </div>
      </div>
    </section>
  );
};

export default Signin;
